using REslava.Result.Flow.Generators.ResultFlow;
using System.Collections.Immutable;
using System.Linq;

namespace REslava.Result.Flow.Tests;

/// <summary>
/// Tests for the <c>{MethodName}_Traced</c> extension generated by REslava.Result.Flow.
/// Verifies that the generator emits the correct try/finally wrapper that seeds
/// <c>PipelineState</c> and fires <c>PipelineObserver</c> events.
/// </summary>
[TestClass]
public class TracedExtensionTests
{
    // ── Basic emission ────────────────────────────────────────────────────────

    [TestMethod]
    public void TracedExtension_EmittedForNonStaticResultFlowMethod()
    {
        var source = CreateSource("OrderService", "PlaceOrder",
            "CreateOrder().Bind(SaveOrder)",
            extraMethods: @"
        static Result<Order> CreateOrder() => Result<Order>.Ok(new Order());
        static Result<Order> SaveOrder(Order o) => Result<Order>.Ok(o);");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("PlaceOrder_Traced"),
            "Generator should emit PlaceOrder_Traced extension method");
        Assert.IsTrue(output.Contains("OrderService_Traced_Extensions"),
            "Generator should emit OrderService_Traced_Extensions class");
    }

    [TestMethod]
    public void TracedExtension_ContainsBeginPipelineCall()
    {
        var source = CreateSource("OrderService", "PlaceOrder",
            "CreateOrder().Bind(SaveOrder)",
            extraMethods: @"
        static Result<Order> CreateOrder() => Result<Order>.Ok(new Order());
        static Result<Order> SaveOrder(Order o) => Result<Order>.Ok(o);");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("global::REslava.Result.PipelineObserver.BeginPipeline("),
            "Generated wrapper should call PipelineObserver.BeginPipeline");
        Assert.IsTrue(output.Contains("\"PlaceOrder\""),
            "BeginPipeline call should pass the method name");
    }

    [TestMethod]
    public void TracedExtension_ContainsNodeIdsStaticField()
    {
        var source = CreateSource("OrderService", "PlaceOrder",
            "CreateOrder().Bind(SaveOrder)",
            extraMethods: @"
        static Result<Order> CreateOrder() => Result<Order>.Ok(new Order());
        static Result<Order> SaveOrder(Order o) => Result<Order>.Ok(o);");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("_nodeIds_PlaceOrder"),
            "Generator should emit _nodeIds_PlaceOrder static field");
        Assert.IsTrue(output.Contains("new string[]"),
            "_nodeIds_ should be a string array");
    }

    [TestMethod]
    public void TracedExtension_ContainsTryFinallyWithDispose()
    {
        var source = CreateSource("OrderService", "PlaceOrder",
            "CreateOrder().Bind(SaveOrder)",
            extraMethods: @"
        static Result<Order> CreateOrder() => Result<Order>.Ok(new Order());
        static Result<Order> SaveOrder(Order o) => Result<Order>.Ok(o);");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("try"),
            "Generated wrapper should have a try block");
        Assert.IsTrue(output.Contains("finally"),
            "Generated wrapper should have a finally block");
        Assert.IsTrue(output.Contains("scope.Dispose()"),
            "finally block should call scope.Dispose()");
    }

    [TestMethod]
    public void TracedExtension_ScopeEndCalledWithResultValues()
    {
        var source = CreateSource("OrderService", "PlaceOrder",
            "CreateOrder().Bind(SaveOrder)",
            extraMethods: @"
        static Result<Order> CreateOrder() => Result<Order>.Ok(new Order());
        static Result<Order> SaveOrder(Order o) => Result<Order>.Ok(o);");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("scope.End("),
            "Generated wrapper should call scope.End");
        Assert.IsTrue(output.Contains("result.IsSuccess"),
            "scope.End should pass result.IsSuccess");
    }

    [TestMethod]
    public void TracedExtension_ReturnValuePassedThrough()
    {
        var source = CreateSource("OrderService", "PlaceOrder",
            "CreateOrder().Bind(SaveOrder)",
            extraMethods: @"
        static Result<Order> CreateOrder() => Result<Order>.Ok(new Order());
        static Result<Order> SaveOrder(Order o) => Result<Order>.Ok(o);");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("return result;"),
            "Generated wrapper should return the result from the real method");
    }

    // ── Static method exclusion ───────────────────────────────────────────────

    [TestMethod]
    public void TracedExtension_NotEmittedForStaticMethod()
    {
        // Static methods cannot have extension methods — generator should skip them
        var source = $@"
using System;
using System.Collections.Immutable;

namespace REslava.Result
{{
    public interface IReason {{ string Message {{ get; }} }}
    public interface IError : IReason {{ }}
    public interface ISuccess : IReason {{ }}
    public interface IResultBase
    {{
        bool IsSuccess {{ get; }}
        bool IsFailure {{ get; }}
        ImmutableList<IReason> Reasons {{ get; }}
        ImmutableList<IError> Errors {{ get; }}
        ImmutableList<ISuccess> Successes {{ get; }}
    }}
    public interface IResultBase<out T> : IResultBase {{ T? Value {{ get; }} }}
    public class Result<T> : IResultBase<T>
    {{
        public bool IsSuccess {{ get; }}
        public bool IsFailure {{ get; }}
        public T? Value {{ get; }}
        public ImmutableList<IReason> Reasons => ImmutableList<IReason>.Empty;
        public ImmutableList<IError> Errors => ImmutableList<IError>.Empty;
        public ImmutableList<ISuccess> Successes => ImmutableList<ISuccess>.Empty;
        public static Result<T> Ok(T value) => new Result<T>();
        public static Result<T> Fail(string msg) => new Result<T>();
        public Result<TOut> Bind<TOut>(Func<T, Result<TOut>> f) => new Result<TOut>();
        public Result<TOut> Map<TOut>(Func<T, TOut> f) => new Result<TOut>();
    }}
}}

namespace TestNS
{{
    using REslava.Result;
    public class Order {{ }}
    public class OrderService
    {{
        [REslava.Result.Flow.ResultFlow]
        public static Result<Order> StaticPipeline() =>
            Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o));
    }}
}}";

        var output = RunGenerator(source);

        // _Traced_Extensions may be absent, or if present, must not have StaticPipeline_Traced
        Assert.IsFalse(output.Contains("StaticPipeline_Traced"),
            "Generator should NOT emit _Traced for static methods");
    }

    // ── Method with parameters ────────────────────────────────────────────────

    [TestMethod]
    public void TracedExtension_MethodWithParameter_ForwardsToRealMethod()
    {
        var source = $@"
using System;
using System.Collections.Immutable;

namespace REslava.Result
{{
    public interface IReason {{ string Message {{ get; }} }}
    public interface IError : IReason {{ }}
    public interface ISuccess : IReason {{ }}
    public interface IResultBase
    {{
        bool IsSuccess {{ get; }}
        bool IsFailure {{ get; }}
        ImmutableList<IReason> Reasons {{ get; }}
        ImmutableList<IError> Errors {{ get; }}
        ImmutableList<ISuccess> Successes {{ get; }}
    }}
    public interface IResultBase<out T> : IResultBase {{ T? Value {{ get; }} }}
    public class Result<T> : IResultBase<T>
    {{
        public bool IsSuccess {{ get; }}
        public bool IsFailure {{ get; }}
        public T? Value {{ get; }}
        public ImmutableList<IReason> Reasons => ImmutableList<IReason>.Empty;
        public ImmutableList<IError> Errors => ImmutableList<IError>.Empty;
        public ImmutableList<ISuccess> Successes => ImmutableList<ISuccess>.Empty;
        public static Result<T> Ok(T value) => new Result<T>();
        public static Result<T> Fail(string msg) => new Result<T>();
        public Result<TOut> Bind<TOut>(Func<T, Result<TOut>> f) => new Result<TOut>();
    }}
}}

namespace TestNS
{{
    using REslava.Result;
    public class CreateOrderRequest {{ }}
    public class Order {{ }}
    public class OrderService
    {{
        [REslava.Result.Flow.ResultFlow]
        public Result<Order> PlaceOrder(CreateOrderRequest request) =>
            Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o));
    }}
}}";

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("PlaceOrder_Traced"),
            "Generator should emit PlaceOrder_Traced for method with parameters");
        // The generated method should forward the parameter to the real method
        Assert.IsTrue(output.Contains("self.PlaceOrder("),
            "Generated wrapper should forward to self.PlaceOrder(...)");
    }

    // ── this OrderService self receiver ──────────────────────────────────────

    [TestMethod]
    public void TracedExtension_UsesThisSelfReceiver()
    {
        var source = CreateSource("OrderService", "PlaceOrder",
            "CreateOrder().Bind(SaveOrder)",
            extraMethods: @"
        static Result<Order> CreateOrder() => Result<Order>.Ok(new Order());
        static Result<Order> SaveOrder(Order o) => Result<Order>.Ok(o);");

        var output = RunGenerator(source);

        // Extension method syntax: this {TypeFqn} self
        Assert.IsTrue(output.Contains("self"),
            "Generated extension method should use 'self' as the receiver parameter");
        Assert.IsTrue(output.Contains("self.PlaceOrder("),
            "Generated wrapper should call self.PlaceOrder(...)");
    }

    // ── Namespace — emitted inside Generated.ResultFlow ───────────────────────

    [TestMethod]
    public void TracedExtension_EmittedInsideGeneratedResultFlowNamespace()
    {
        var source = CreateSource("OrderService", "PlaceOrder",
            "CreateOrder().Bind(SaveOrder)",
            extraMethods: @"
        static Result<Order> CreateOrder() => Result<Order>.Ok(new Order());
        static Result<Order> SaveOrder(Order o) => Result<Order>.Ok(o);");

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("namespace Generated.ResultFlow"),
            "Both the Flows constants and _Traced_Extensions should be in Generated.ResultFlow namespace");
    }

    // ── Multiple methods on same class ───────────────────────────────────────

    [TestMethod]
    public void TracedExtension_TwoMethodsSameClass_BothEmitted()
    {
        var source = $@"
using System;
using System.Collections.Immutable;

namespace REslava.Result
{{
    public interface IReason {{ string Message {{ get; }} }}
    public interface IError : IReason {{ }}
    public interface ISuccess : IReason {{ }}
    public interface IResultBase
    {{
        bool IsSuccess {{ get; }}
        bool IsFailure {{ get; }}
        ImmutableList<IReason> Reasons {{ get; }}
        ImmutableList<IError> Errors {{ get; }}
        ImmutableList<ISuccess> Successes {{ get; }}
    }}
    public interface IResultBase<out T> : IResultBase {{ T? Value {{ get; }} }}
    public class Result<T> : IResultBase<T>
    {{
        public bool IsSuccess {{ get; }}
        public bool IsFailure {{ get; }}
        public T? Value {{ get; }}
        public ImmutableList<IReason> Reasons => ImmutableList<IReason>.Empty;
        public ImmutableList<IError> Errors => ImmutableList<IError>.Empty;
        public ImmutableList<ISuccess> Successes => ImmutableList<ISuccess>.Empty;
        public static Result<T> Ok(T value) => new Result<T>();
        public static Result<T> Fail(string msg) => new Result<T>();
        public Result<TOut> Bind<TOut>(Func<T, Result<TOut>> f) => new Result<TOut>();
    }}
}}

namespace TestNS
{{
    using REslava.Result;
    public class Order {{ }}
    public class Invoice {{ }}
    public class OrderService
    {{
        [REslava.Result.Flow.ResultFlow]
        public Result<Order> PlaceOrder() =>
            Result<Order>.Ok(new Order()).Bind(o => Result<Order>.Ok(o));

        [REslava.Result.Flow.ResultFlow]
        public Result<Invoice> CreateInvoice() =>
            Result<Invoice>.Ok(new Invoice()).Bind(i => Result<Invoice>.Ok(i));
    }}
}}";

        var output = RunGenerator(source);

        Assert.IsTrue(output.Contains("PlaceOrder_Traced"),
            "First method should have _Traced emitted");
        Assert.IsTrue(output.Contains("CreateInvoice_Traced"),
            "Second method should have _Traced emitted");
        Assert.IsTrue(output.Contains("_nodeIds_PlaceOrder"),
            "First method should have _nodeIds_ field");
        Assert.IsTrue(output.Contains("_nodeIds_CreateInvoice"),
            "Second method should have _nodeIds_ field");
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    private static string CreateSource(
        string className,
        string methodName,
        string returnExpression,
        string extraMethods = "")
    {
        return $@"
using System;
using System.Collections.Immutable;

namespace REslava.Result
{{
    public interface IReason {{ string Message {{ get; }} }}
    public interface IError : IReason {{ }}
    public interface ISuccess : IReason {{ }}
    public interface IResultBase
    {{
        bool IsSuccess {{ get; }}
        bool IsFailure {{ get; }}
        ImmutableList<IReason> Reasons {{ get; }}
        ImmutableList<IError> Errors {{ get; }}
        ImmutableList<ISuccess> Successes {{ get; }}
    }}
    public interface IResultBase<out T> : IResultBase {{ T? Value {{ get; }} }}
    public class Result<T> : IResultBase<T>
    {{
        public bool IsSuccess {{ get; }}
        public bool IsFailure {{ get; }}
        public T? Value {{ get; }}
        public ImmutableList<IReason> Reasons => ImmutableList<IReason>.Empty;
        public ImmutableList<IError> Errors => ImmutableList<IError>.Empty;
        public ImmutableList<ISuccess> Successes => ImmutableList<ISuccess>.Empty;
        public static Result<T> Ok(T value) => new Result<T>();
        public static Result<T> Fail(string msg) => new Result<T>();
        public Result<TOut> Bind<TOut>(Func<T, Result<TOut>> f) => new Result<TOut>();
        public Result<TOut> Map<TOut>(Func<T, TOut> f) => new Result<TOut>();
        public Result<T> Tap(Action<T> a) => this;
        public Result<T> Ensure(Func<T, bool> p, Func<T, IError> e) => this;
    }}
}}

namespace TestNS
{{
    using REslava.Result;

    public class Order {{ }}
    public class Invoice {{ }}

    public class {className}
    {{
        [REslava.Result.Flow.ResultFlow]
        public Result<Order> {methodName}() => {returnExpression};
        {extraMethods}
    }}
}}";
    }

    private static string RunGenerator(string source)
    {
        var syntaxTree = CSharpSyntaxTree.ParseText(SourceText.From(source));

        var references = new System.Collections.Generic.List<MetadataReference>
        {
            MetadataReference.CreateFromFile(typeof(object).Assembly.Location),
            MetadataReference.CreateFromFile(typeof(Enumerable).Assembly.Location),
            MetadataReference.CreateFromFile(typeof(ImmutableList<>).Assembly.Location),
        };

        var compilation = CSharpCompilation.Create(
            "TracedExtensionTestCompilation",
            new[] { syntaxTree },
            references,
            new CSharpCompilationOptions(OutputKind.DynamicallyLinkedLibrary));

        var generator = new ResultFlowGenerator();
        var driver = CSharpGeneratorDriver.Create(generator);
        var updatedDriver = driver.RunGeneratorsAndUpdateCompilation(compilation, out _, out _);

        var sb = new System.Text.StringBuilder();
        foreach (var tree in updatedDriver.GetRunResult().GeneratedTrees)
        {
            using var writer = new System.IO.StringWriter();
            tree.GetText().Write(writer);
            sb.AppendLine(writer.ToString());
        }
        return sb.ToString();
    }
}
